#include <stdio.h>
#include <string.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar();
    char line[1024];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line,sizeof(line),stdin)) break;
        double sum=0, discount=0, tax=10, tip=15;
        char *token=strtok(line," \n");
        while(token){
            char *sep=strchr(token,':');
            if(sep){
                *sep='\0';
                char *key=token; char *val=sep+1;
                double v=atof(val);
                if(strcmp(key,"discount")==0) discount=v;
                else if(strcmp(key,"tax")==0) tax=v;
                else if(strcmp(key,"tip")==0) tip=v;
                else sum+=v;
            }
            token=strtok(NULL," \n");
        }
        double total=sum*(1.0-discount/100.0);
        total*=1.0+tax/100.0;
        total*=1.0+tip/100.0;
        printf("%.2f\n",total);
    }
    return 0;
}

