import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        String first=br.readLine();
        if(first==null||first.isEmpty()) return;
        int T=Integer.parseInt(first.trim());
        StringBuilder out=new StringBuilder();
        for(int i=0;i<T;i++){
            String line=br.readLine();
            if(line==null) line="";
            double sum=0, discount=0, tax=10, tip=15;
            StringTokenizer st=new StringTokenizer(line);
            while(st.hasMoreTokens()){
                String token=st.nextToken();
                int idx=token.indexOf(':');
                if(idx==-1) continue;
                String key=token.substring(0,idx);
                double val=Double.parseDouble(token.substring(idx+1));
                switch(key){
                    case "discount": discount=val; break;
                    case "tax": tax=val; break;
                    case "tip": tip=val; break;
                    default: sum+=val; break;
                }
            }
            double total=sum*(1-discount/100.0);
            total*=1+tax/100.0;
            total*=1+tip/100.0;
            out.append(String.format(java.util.Locale.US,"%.2f",total)).append('\n');
        }
        System.out.print(out.toString());
    }
}

