#!/usr/bin/env python3
import sys

def solve():
    data=sys.stdin.read().strip().splitlines()
    if not data:
        return
    T=int(data[0])
    out=[]
    for i in range(1,T+1):
        line=data[i].strip() if i<len(data) else ''
        sum_price=0.0
        discount=0.0
        tax=10.0
        tip=15.0
        for token in line.split():
            if ':' not in token:
                continue
            key,val=token.split(':',1)
            v=float(val)
            if key=='discount':
                discount=v
            elif key=='tax':
                tax=v
            elif key=='tip':
                tip=v
            else:
                sum_price+=v
        total=sum_price*(1-discount/100.0)
        total*=1+tax/100.0
        total*=1+tip/100.0
        out.append(f"{total:.2f}")
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    solve()

